import { CallStatus } from '@/types/api.types';

export const mapHttpStatusToCallStatus = (status: number): CallStatus => {
  switch (status) {
    case 429: return CallStatus.Throttled;
    case 400: return CallStatus.BadRequest;
    default:  return CallStatus.Failure;
  }
};

export const getHttpErrorMessage = (status: number): string => {
  switch (status) {
    case 0:   return 'Network error. Please check your internet connection.';
    case 400: return 'Invalid request. Please check your input and try again.';
    case 401: return 'Unauthorized. Please login again.';
    case 429: return 'Too many requests. Please wait a moment before trying again.';
    case 500: return 'Server error. Please try again later.';
    default:  return 'An error occurred while fetching data.';
  }
};
